export const rcActivities: Activity[] = [
  {"id":"rc-cardboard-loom-weaving","title":"Cardboard Loom Weaving","altNames":["DIY loom weaving","cardboard weaving","yarn mat weaving","woven coaster"],"type":"Craft","place":"Both","ageMin":9,"ageMax":18,"durationMin":45,"groupMin":null,"groupMax":null,"energy":1,"prep":"Low","blurb":"Notch a piece of cardboard, string it up, and weave a real fabric coaster or wall hanging from scrap yarn.","materials":["Cardboard rectangles, ~5x7 in, 1 per camper","Yarn in several colors","Scissors","Masking tape","A blunt-tipped weaving needle cut from cardboard or a clothespin per camper","Markers"],"materialTags":["Cardboard","Yarn","Scissors","Masking tape","Clothespins","Markers"],"steps":["Cut shallow notches about a half-inch apart along the two short ends of each cardboard rectangle, lining the top and bottom notches up.","String the warp by taping a yarn tail to the back, running the yarn up through the first top notch, straight down to the matching bottom notch, around the back, and up again until every notch is filled, then tape the end.","Tie a long working strand (the weft) to a cardboard 'needle' and weave it over-one, under-one across the warp threads.","On the return pass weave the opposite sequence (under the threads you went over) and gently push each row down snug against the last.","Change colors by tying a new strand to the old one at the edge, keeping knots on the back side of the loom.","When the weaving fills the loom, cut the warp threads off the back, tie pairs of loose ends together, and trim the fringe even."],"notes":"Demo one full over-under row on a big loom so everyone sees the pattern before they start. Pair fast finishers with strugglers as helpers, and remind kids that pushing rows tight is what makes it look like real cloth. To scale up for older grades, have them weave wider pieces, plan a deliberate stripe or checkerboard color pattern, or combine several finished panels into a bag or wall hanging.","safety":"The cardboard needles and notch-cutting use scissors near fingers; cut notches yourself for younger groups and keep blade-cutting motions pointed away from the hand holding the cardboard.","ages":["g46","g79","g1012"],"rating":4,"media":[{"title":"How to Make a Cardboard Loom | Step by Step | Art for Kids — video tutorial","url":"https://www.youtube.com/watch?v=GQHf8TlYC50"}],"links":[{"label":"Our Days Outside: classic summer camp crafts","url":"https://ourdaysoutside.com/15-classic-summer-camp-crafts-for-kids/"}],"variations":["Set the warp notches farther apart and use chunky yarn for a fast, beginner-friendly version.","Weave on a round cardboard disk with an odd number of notches to make a woven sun catcher or mandala.","For older campers, challenge them to weave a recognizable picture or their initials by counting threads and planning color blocks like pixel art.","Leave long warp loops at the top so the finished weaving can hang from a stick as a wall banner."],"subsets":[["Mark the notch spacing with a ruler or a folded paper template first","Cut all notches on one end before flipping to the other"],[],["Tape the weft tail down so it does not pull loose on the first pass"],["Tug too hard and the edges pull in, so keep the weft loose at the turn"],[],["Slide the weaving off rather than yanking so rows do not unravel"]]},
  {"id":"rc-ojo-de-dios","title":"Ojo de Dios Yarn Diamonds","altNames":["God's eye","ojo de dios","yarn god's eye","stick weaving"],"type":"Craft","place":"Both","ageMin":9,"ageMax":18,"durationMin":30,"groupMin":null,"groupMax":null,"energy":1,"prep":"Low","blurb":"Wrap colorful yarn around two crossed sticks to weave the traditional diamond-shaped 'eye of god' charm.","materials":["Two sticks, dowels, or sturdy straws per camper, ~8 in each","Yarn in 2-4 colors","Scissors","Pony beads for trim","Masking tape"],"materialTags":["Yarn","Scissors","Pony beads","Masking tape","Straws"],"steps":["Cross two sticks at their centers to form a plus sign and lash them together by wrapping yarn diagonally several times in an X over the joint.","Tie the yarn off snug and begin wrapping: bring the yarn over and around one arm, then carry it to the next arm and wrap that one the same way.","Keep rotating the same direction, wrapping each arm once before moving to the next, so a flat diamond pattern grows outward from the center.","Push each wrap snug against the last and keep tension even so the yarn lies flat without gaps.","To switch colors, cut the yarn, tie on a new color at the back, and continue wrapping in the same direction.","Wrap until you near the stick tips, tie off the final strand, and add a pony bead or yarn tassel to each arm."],"notes":"The hardest moment is remembering to always wrap the same direction; have campers chant 'over, around, next stick' as a rhythm. Keep wraps snug or the diamond looks loose and messy. For older grades, give them three or four sticks for a six- or eight-point star, or have them plan a precise color-stripe sequence to make concentric rings.","safety":"Stick or dowel tips can poke eyes if waved around; have campers keep the project flat on the table and lower whenever they turn to talk to a neighbor.","ages":["g46","g79","g1012"],"rating":4,"media":[{"title":"How to Make a God's Eye with 2 Sticks — video tutorial","url":"https://www.youtube.com/watch?v=MXiCqWRTn_M"}],"links":[{"label":"Our Days Outside: classic summer camp crafts","url":"https://ourdaysoutside.com/15-classic-summer-camp-crafts-for-kids/"}],"variations":["Use two straws taped in a cross for an indoor, splinter-free version younger campers can handle.","Make a mini ojo with short sticks and hang several from a longer stick as a mobile.","For older campers, build a four-stick eight-point star and challenge them to keep two interlocking color patterns aligned across all arms.","Wrap a wide white or pale band in the middle and tighter colored rings outside to make it read like a real eye."],"subsets":[["Hold the cross tight while you lash so the arms stay at right angles"],[],["If you lose the rhythm, stop and check which arm the yarn last came from"],[],["Knot color changes on the back so the front stays clean"],[]]},
  {"id":"rc-nature-mandalas","title":"Nature Mandalas","altNames":["nature mandala","leaf mandala","outdoor nature art","found-object circle art"],"type":"Craft","place":"Outside","ageMin":9,"ageMax":18,"durationMin":30,"groupMin":null,"groupMax":null,"energy":1,"prep":"None","blurb":"Hunt for leaves, petals, pebbles, and seeds, then arrange them into a radiating symmetrical mandala on the ground.","materials":["Found natural items gathered on site (leaves, pebbles, petals, seed pods, sticks)","Paper plates or sidewalk chalk to mark a center","A phone or counselor camera to photograph finished work"],"materialTags":["Paper plates","Sidewalk chalk"],"steps":["Give each camper or pair a few minutes to forage a handful of natural objects, sorting them by color, size, and shape.","Mark a center point on the ground or on a paper plate with chalk and place one special object there.","Build the first ring by placing matching objects evenly around the center, like spokes on a wheel.","Add each new ring outward, keeping every ring's pieces the same so the design stays balanced and symmetrical.","Step back, fill any gaps, and tweak colors so the rings contrast and the pattern radiates cleanly.","Photograph each finished mandala, then have campers scatter the materials back to nature as a 'leave no trace' close."],"notes":"This works great as a calm reset after a high-energy block. Emphasize that nothing gets glued or taken home, only photographed, which keeps cleanup to zero. For older grades, require true rotational symmetry, a deliberate color gradient from center to edge, or a collaborative giant mandala the whole group builds together.","safety":"Set picking boundaries before foraging: only pick fallen items, never berries or mushrooms, and wash hands after since unknown plants and sap can irritate skin.","ages":["g46","g79","g1012"],"rating":4,"media":[{"title":"How to Make Nature Mandalas — video tutorial","url":"https://www.youtube.com/watch?v=_73B7JL_cUc"}],"links":[{"label":"Little Bins for Little Hands: summer camp activities","url":"https://littlebinsforlittlehands.com/summer-camp-activities/"}],"variations":["Hand out paper plates as the base so each mandala stays contained and easy to compare.","Run it as a speed round where campers build the fullest symmetrical mandala in five minutes.","For older campers, assign Andy Goldsworthy as inspiration and require a documented color gradient plus a written caption explaining their design choices.","Build one enormous group mandala with each small team responsible for one ring, coordinating colors as they go."],"subsets":[["Set a clear foraging boundary and a return-by signal","Sort finds into piles by color before building"],[],[],["If a ring looks crowded, remove pieces rather than cramming more in"],[],["Take the photo from directly overhead for the best symmetry"]]},
  {"id":"rc-leaf-rubbings","title":"Leaf Rubbing Art","altNames":["leaf rubbing","crayon leaf rubbing","nature texture art","bark rubbings"],"type":"Craft","place":"Both","ageMin":9,"ageMax":15,"durationMin":30,"groupMin":null,"groupMax":null,"energy":1,"prep":"Low","blurb":"Lay paper over a leaf and rub the side of a crayon across it to reveal every vein and edge like a secret print.","materials":["Assorted leaves with strong veins, several per camper","Thin paper, 2-3 sheets per camper","Crayons with wrappers peeled","Markers for labeling","Masking tape"],"materialTags":["Paper","Crayons","Markers","Masking tape"],"steps":["Collect leaves with raised veins and varied shapes, choosing fresh flat ones rather than dry crumbly ones.","Place a leaf vein-side up on the table and tape it down at the stem so it can't slide.","Lay a sheet of paper over the leaf and tape the paper corners to hold everything still.","Peel the wrapper off a crayon, lay the crayon on its side, and rub it back and forth flat across the paper over the leaf.","Keep rubbing until the full leaf shape and all its veins appear, then move to a new spot or new leaf and overlap prints.","Label each print with the leaf's name or where it was found, and arrange several into a collage or nature journal page."],"notes":"The whole trick is rubbing with the crayon's side, not the tip, and not pressing too hard; demo both so kids feel the difference. Overlapping prints in different colors makes a richer page. For older grades, turn it into a botany task where they identify each leaf, compare vein patterns, and build a labeled field-guide page.","safety":"Leaf edges and stems can be surprisingly sharp and some plants cause rashes, so pre-check the gathered leaves and avoid anything with three-leaf clusters or milky sap.","ages":["g46","g79"],"rating":3,"media":[{"title":"How to Make Leaf Rubbing Art — video tutorial","url":"https://www.youtube.com/watch?v=W66TAqCT4hc"}],"links":[{"label":"Little Bins for Little Hands: summer camp activities","url":"https://littlebinsforlittlehands.com/summer-camp-activities/"}],"variations":["Add bark, coins, and textured cardboard to the rubbing hunt for a mixed-texture page.","Make a color-blended sunset background by rubbing several crayon colors in horizontal bands behind the leaves.","For older campers, run it as a leaf-identification challenge: rub, key out the species, and assemble a labeled field-guide spread.","Cut finished rubbings out and glue them onto a folded card to make nature-print greeting cards."],"subsets":[[],["Tape only the stem so the leaf lies flat without bulging"],[],["Long even strokes work better than scribbling in circles","Switch colors for different leaves to keep prints distinct"],[],["Group prints by leaf type to compare shapes side by side"]]},
  {"id":"rc-nature-weaving-frame","title":"Nature Weaving Frame","altNames":["nature weaving","stick loom weaving","branch weaving","woven nature frame"],"type":"Craft","place":"Both","ageMin":9,"ageMax":18,"durationMin":45,"groupMin":null,"groupMax":null,"energy":1,"prep":"Low","blurb":"String yarn across a forked-stick or cardboard frame, then weave in foraged grasses, leaves, and flowers.","materials":["A Y-shaped stick or cardboard rectangle frame per camper","Yarn","Scissors","Foraged grasses, long leaves, flowers, and feathers","Masking tape"],"materialTags":["Cardboard","Yarn","Scissors","Masking tape"],"steps":["Choose a sturdy forked stick or cut a cardboard rectangle with notches as the loom frame.","Tie the yarn to one side and wrap it back and forth across the opening, spacing the strands about a finger-width apart to form the warp.","Tie off the warp and gently push the strands so they are evenly spaced and taut.","Forage long flexible natural pieces like grass blades, fern fronds, and flower stems.","Weave each piece over and under the yarn strands, alternating the start so they lock in, and slide them snug together.","Keep adding layers and colors until the frame is full, tuck the loose ends, and tie a yarn loop at the top for hanging."],"notes":"Fresh bendy grasses and ferns weave far better than stiff twigs, so steer the forage that way. Spacing the warp too tightly makes weaving frustrating, so keep gaps generous. For older grades, push for a designed color and texture composition, a tighter warp for fine detail, or a large shared frame woven as a group tapestry.","safety":"Forking and notching frames involves scissors and stick ends; keep the frame flat while weaving and have a counselor cut any thick sticks rather than campers forcing scissors through them.","ages":["g46","g79","g1012"],"rating":4,"media":[{"title":"2 Ways of Nature Weaving with Kids | Welcome to Nana's — video tutorial","url":"https://www.youtube.com/watch?v=lr6aMsZMOKc"}],"links":[{"label":"Our Days Outside: classic summer camp crafts","url":"https://ourdaysoutside.com/15-classic-summer-camp-crafts-for-kids/"}],"variations":["Use a cardboard frame instead of a stick so every camper has an even, easy-to-string loom.","Pre-warp the frames yourself for younger or rushed groups so they jump straight to weaving.","For older campers, require a planned composition with foreground and background layers and a written artist statement about their material choices.","Combine each camper's small woven panel into one giant group wall hanging tied between two poles."],"subsets":[["Pick a fork wide enough to weave inside comfortably"],["Keep even tension so the warp does not bow inward"],[],["Gather extra so you can choose the bendiest pieces"],["Alternate over-under each row or the weave falls apart"],[]]},
  {"id":"rc-cardboard-marble-maze","title":"Cardboard Marble Maze","altNames":["marble maze","tilt maze","cardboard labyrinth","marble run maze"],"type":"Craft","place":"Both","ageMin":9,"ageMax":18,"durationMin":60,"groupMin":null,"groupMax":null,"energy":2,"prep":"Medium","blurb":"Engineer a tilt-and-roll marble maze from a cardboard box lid, scrap walls, and a few sneaky pitfall holes.","materials":["Shallow cardboard box lids or trays, 1 per camper","Scrap cardboard strips for walls","Marbles or pony beads, 1-2 per camper","Glue","Masking tape","Scissors","Markers"],"materialTags":["Cardboard","Glue","Masking tape","Scissors","Markers","Pony beads"],"steps":["Plan a path from a start corner to a finish corner with pencil so you know where the walls go.","Cut scrap cardboard into thin strips and fold a small flap along one edge of each so it can be glued standing up.","Glue or tape the strips upright along your planned path to make the maze walls.","Poke a few 'trap' holes through the floor near tricky turns so a misguided marble drops out and you have to restart.","Decorate the start, finish, and trap zones with markers, then let the glue set.","Test by tilting the tray to roll the marble through, then adjust wall angles and add or remove traps to tune the difficulty."],"notes":"Have campers sketch the path before gluing, since walls are hard to move once stuck. Pony beads roll slower than marbles and are easier for first tries. For older grades, require multiple branching paths, a timed difficulty target, or moving obstacles like a swinging cardboard gate, and let them swap mazes to race each other's builds.","safety":"Watch the glue and small marbles around mouths and eyes; keep marbles in a cup until building is done and remind campers that traps are for the marble, not for poking fingers through.","ages":["g46","g79","g1012"],"rating":5,"media":[{"title":"How to make a Marble Maze | DIY Cardboard Games — video tutorial","url":"https://www.youtube.com/watch?v=vkFwreUAW4c"}],"links":[{"label":"Little Bins for Little Hands: summer camp activities","url":"https://littlebinsforlittlehands.com/summer-camp-activities/"}],"variations":["Skip traps and keep a single simple path for younger or time-crunched groups.","Add tunnels made from straws or rolled paper that the marble must roll through.","For older campers, require at least two dead-end branches plus a scoring system, then run a tournament timing each maze with a swapped marble.","Make a tilt-table version glued onto a larger base with handles so the whole maze tips like a commercial labyrinth toy."],"subsets":[["Mark start and finish first, then draw the winding path between"],["Fold a glue tab so walls have a base to stick down","Cut walls slightly taller than the marble"],[],["Place traps just after a turn where marbles speed up"],[],["If the marble jumps walls, lower the tilt angle and reinforce corners"]]},
  {"id":"rc-bottle-cap-mosaics","title":"Bottle-Cap and Scrap Mosaics","altNames":["bottle cap mosaic","recycled mosaic","cap art","scrap mosaic"],"type":"Craft","place":"Both","ageMin":9,"ageMax":18,"durationMin":45,"groupMin":null,"groupMax":null,"energy":1,"prep":"Medium","blurb":"Turn saved bottle caps, torn paper, and pony beads into a chunky mosaic picture glued onto cardboard.","materials":["Collected bottle caps and lids","Cardboard base squares, 1 per camper","Torn colored paper scraps","Pony beads","Glue","Markers","Pencils"],"materialTags":["Cardboard","Glue","Pony beads","Paper","Markers"],"steps":["Lightly pencil a simple bold outline on the cardboard, like a sun, fish, or initial, keeping shapes large.","Sort the bottle caps, paper scraps, and beads into color piles so you can grab by color while building.","Dry-lay the caps and pieces inside your outline first, without glue, to plan the color layout.","Glue the pieces down one section at a time, pressing each firmly and leaving small even gaps like real mosaic tile.","Fill the background around your shape with a contrasting color so the picture pops.","Let it dry flat, then outline shapes with marker if you want crisper edges."],"notes":"Collecting caps in advance is the real prep; ask families or save them across earlier weeks. Big simple shapes read far better than detailed ones in chunky mosaic. For older grades, push for shading with color gradients, a recognizable portrait or logo, or a large collaborative mural where each camper tiles one section of a shared design.","safety":"Some bottle caps have sharp metal rims or edges; pre-sort and remove any jagged metal caps, and keep beads and caps out of mouths for the whole session.","ages":["g46","g79","g1012"],"rating":4,"links":[{"label":"Bottle Cap Mosaic — Education.com activity guide","url":"https://www.education.com/activity/article/bottle-cap-mosaic/"},{"label":"Little Bins for Little Hands: summer camp activities","url":"https://littlebinsforlittlehands.com/summer-camp-activities/"}],"variations":["Use only torn paper scraps for a no-cap version if you have not collected enough lids.","Make tiny coaster-sized mosaics so everyone finishes within a short block.","For older campers, assign a shaded color gradient or a real logo recreation and require even tile spacing throughout.","Run a mural version where the group tiles letters spelling the camp name across several joined cardboard panels."],"subsets":[["Keep the drawing bold and simple, no thin lines"],["Sort by color into cups so building goes fast"],["Plan before gluing so you do not run out of a color mid-shape"],[],[],[]]},
  {"id":"rc-paper-bag-kites","title":"Paper-Bag Kites","altNames":["paper bag kite","lunch bag kite","simple sled kite","DIY kite"],"type":"Craft","place":"Both","ageMin":9,"ageMax":15,"durationMin":45,"groupMin":null,"groupMax":null,"energy":2,"prep":"Low","blurb":"Decorate a paper bag, punch a string bridle, and tape on a streamer tail to make a kite that actually catches the breeze.","materials":["Paper lunch bags, 1 per camper","String or yarn, ~4 ft per camper","Markers and crayons","Paper strips for the tail","Straws to reinforce the mouth","Masking tape","Scissors","Hole reinforcement made from tape"],"materialTags":["Paper bags","Yarn","Markers","Crayons","Straws","Masking tape","Scissors","Paper"],"steps":["Decorate the flat paper bag with markers and crayons, drawing a face, creature, or bold pattern.","Tape a straw across the open mouth of the bag to hold it open and stiff as the kite's leading edge.","Reinforce two spots on the open rim with folded tape, then punch a small hole through each reinforced spot.","Thread the string through both holes and tie it into a loop bridle so the bag tips its mouth into the wind.","Tape several paper streamers to the closed bottom of the bag to make a stabilizing tail.","Tie a long flying line to the middle of the bridle, then run into the wind to launch and let it climb."],"notes":"A light breeze and an open field make or break this one, so check conditions and pick the windward side of the field. Reinforcing the string holes is the step kids skip and then rip out, so insist on it. For older grades, have them test tail length and bridle position as variables, compare flight, and redesign for the best altitude.","safety":"Kite-flyers watch the kite, not their feet, so set wide spacing and a no-run zone near fences, roads, and overhead power lines, and never fly in a storm.","ages":["g46","g79"],"rating":3,"links":[{"label":"Paper Grocery Bag Kites — KinderArt crafts lesson (grades K-8)","url":"https://kinderart.com/art-lessons/crafts/paper-bag-kites/"},{"label":"S&S Blog: top summer camp themes","url":"https://www.ssww.com/blog/top-10-summer-camp-themes-creative-engaging-activity-ideas/"}],"variations":["Pre-punch and pre-string the bridle for younger campers so they only decorate and fly.","Add a longer or weighted tail and see how it changes stability in gusty wind.","For older campers, turn it into a controlled experiment varying tail length and bridle angle, charting which combo flies highest.","Hold a no-wind challenge where campers must run to keep their kite aloft the longest."],"subsets":[[],["The straw keeps the mouth open so air can fill the bag"],["Double-fold tape over the holes or the string tears out"],["Make the loop even so the bag pulls straight"],[],["Run smoothly into the wind, do not jerk the line"]]},
  {"id":"rc-cardboard-binoculars","title":"Cardboard Explorer Binoculars","altNames":["toilet roll binoculars","cardboard binoculars","explorer binoculars","nature spy binoculars"],"type":"Craft","place":"Both","ageMin":9,"ageMax":12,"durationMin":30,"groupMin":null,"groupMax":null,"energy":1,"prep":"Low","blurb":"Tape two cardboard tubes together, add a yarn neck strap, and head out on a nature spotting mission.","materials":["Cardboard tubes, 2 per camper","Yarn or string for a strap","Markers, crayons, paint","Paper scraps to wrap and decorate","Glue","Masking tape","Scissors","Hole punch or pencil"],"materialTags":["Cardboard","Yarn","Markers","Paint","Paper","Glue","Masking tape","Scissors"],"steps":["Wrap each cardboard tube in paper or paint and decorate it with markers in your own explorer style.","Set the two tubes side by side and tape them firmly together along their length.","Punch or poke a small hole near the outer top edge of each tube.","Cut a length of yarn for a neck strap and tie one end through each hole.","Let any paint or glue dry, then add a 'lens' ring of marker around the front rim if you like.","Take the binoculars outside and use them to frame and spot birds, bugs, clouds, and far-off landmarks on a quick scavenger hunt."],"notes":"This is a quick build that pairs perfectly with a follow-on nature walk, so plan the two back to back. Tape the tubes well or they twist apart in little hands. To stretch it for the upper end of this band, add a paper 'focus' slider or pair it with a real spotting checklist and observation journal.","safety":"Remind campers the binoculars are toys with no real lenses and must never be pointed at the sun, and to walk while looking through them only in open clear areas.","ages":["g46"],"rating":3,"links":[{"label":"DIY Craft: How to Make Cardboard Binoculars for Kids — Audubon","url":"https://www.audubon.org/news/diy-craft-how-make-cardboard-binoculars-kids"},{"label":"Our Days Outside: classic summer camp crafts","url":"https://ourdaysoutside.com/15-classic-summer-camp-crafts-for-kids/"}],"variations":["Make a single-tube spyglass instead of double binoculars for a pirate theme day.","Add a paper 'focus ring' that slides on the front tube for older kids who want detail.","Pair with a printed scavenger-hunt checklist so the binoculars get used right after the build.","Decorate as themed gear (jungle explorer, ocean diver, astronaut) to match the day's camp theme."],"subsets":[[],["Tape the full length, not just the ends, so they stay aligned"],["Make holes on the outer edges so the strap hangs evenly"],[],[],["Give a short spotting list so kids have targets to find"]]},
  {"id":"rc-pinecone-bird-feeders","title":"Pinecone Bird Feeders","altNames":["pinecone feeder","bird feeder craft","seed pinecone feeder","nature bird feeder"],"type":"Craft","place":"Both","ageMin":9,"ageMax":15,"durationMin":30,"groupMin":null,"groupMax":null,"energy":1,"prep":"Medium","blurb":"Slather a pinecone in sticky spread, roll it in birdseed, and hang it outside as a feast for local birds.","materials":["Open pinecones, 1 per camper","Yarn or string, ~18 in per camper","Spreadable peanut butter or seed butter (check allergies) or vegetable shortening","Birdseed in a shallow tray","Plastic knives or craft sticks","Paper plates","Paper towels"],"materialTags":["Yarn","Paper plates","Paper towels"],"steps":["Tie a loop of yarn securely around the top few rows of the pinecone so it can hang later.","Set the pinecone on a paper plate and use a craft stick to spread sticky butter or shortening into all the gaps and scales.","Hold the pinecone over a tray and spoon or roll birdseed over it, pressing gently so seed sticks everywhere.","Gently shake off loose seed back into the tray and patch any bare spots.","Carry the feeder outside and hang it from a branch, fence, or hook where birds can reach but cats cannot.","Over the next days, check the feeder and keep a tally of which birds visit."],"notes":"Allergy check is non-negotiable; use sunflower-seed butter or plain vegetable shortening if any camper has a nut allergy. Tie the hanging loop before the sticky step so no one gums up the knot. For older grades, add a bird-identification log, compare which seed mix or hanging spot attracts more visitors, and graph the results over the week.","safety":"Confirm no nut allergies before choosing a spread and keep the sticky butter away from faces; hands get very messy, so station paper towels and a hand-wash break right after.","ages":["g46","g79"],"rating":4,"links":[{"label":"How to Make Pinecone Bird Feeders — One Little Project","url":"https://onelittleproject.com/pinecone-bird-feeders/"},{"label":"Rustic Pathways: summer camp activities","url":"https://rusticpathways.com/blog/summer-camp-activities"}],"variations":["Use vegetable shortening rolled in cornmeal-and-seed mix for a fully nut-free version.","Make a cardboard-tube feeder instead of a pinecone if pinecones are scarce, coating the tube the same way.","For older campers, set up feeders in different spots and run a week-long study charting bird visits by location and seed type.","Decorate a paper tag for each feeder naming it, then hang them all along one fence as a feeder trail."],"subsets":[["Tie the loop first so the sticky cone is easy to handle later"],["Work the spread deep into the scales, not just the surface"],["Press seed firmly into the butter so it holds"],[],["Pick a spot safe from cats and visible from a window"],[]]},
  {"id":"rc-nature-mobiles","title":"Hanging Nature Mobiles","altNames":["nature mobile","stick mobile","hanging nature art","found-object mobile"],"type":"Craft","place":"Both","ageMin":9,"ageMax":18,"durationMin":45,"groupMin":null,"groupMax":null,"energy":1,"prep":"Low","blurb":"Balance foraged sticks, leaves, and pinecones on yarn into a dangling, twirling mobile that hangs from a branch.","materials":["A main horizontal stick per camper","Yarn or string","Foraged items (leaves, pinecones, seed pods, feathers, pebbles)","Scissors","Masking tape","Pony beads for accents","Markers"],"materialTags":["Yarn","Scissors","Masking tape","Pony beads","Markers"],"steps":["Choose a strong straight stick as the main crossbar and tie a yarn hanging loop at its center.","Forage and lay out an assortment of light natural objects to dangle.","Tie a length of yarn to each object, using tape or a wrapped knot for slippery items like pebbles.","Hang the objects from the crossbar at different lengths, spacing them so the stick looks full but not crowded.","Test the balance by holding the loop up, then slide the strands left or right until the crossbar hangs level.","Add pony-bead accents along the strands, trim loose ends, and hang the finished mobile from a branch or hook."],"notes":"Balancing is the engineering lesson here: heavier items go nearer the center, lighter ones farther out. Test-hang often so kids fix tilt as they go instead of at the end. For older grades, add a second crossbar tier for a true hierarchical mobile, or require it to balance perfectly level while telling a story through its objects.","safety":"Stick ends and pinecone scales can scratch; keep the crossbar lowered while tying and have a counselor pre-snap any overly long or split sticks.","ages":["g46","g79","g1012"],"rating":4,"links":[{"label":"Beautiful Pinecone and Bead Mobile Craft for Kids — Happy Hooligans","url":"https://happyhooligans.ca/pinecone-mobiles-for-kids-to-make/"},{"label":"Our Days Outside: classic summer camp crafts","url":"https://ourdaysoutside.com/15-classic-summer-camp-crafts-for-kids/"}],"variations":["Pre-tie the hanging loop and pre-cut yarn strands for younger or rushed groups.","Theme the mobile to a color or a single object type, like all leaves or all seed pods.","For older campers, require a balanced two-tier mobile with a smaller crossbar hanging from the main one.","Make a group 'forest' mobile where each camper adds one strand to a long shared branch."],"subsets":[["Pick a stick that does not bend under light weight"],[],["Wrap tape around slippery items before knotting the yarn"],["Vary the lengths so it looks lively, not flat"],["Heavier items belong closer to the center for balance"],[]]},
  {"id":"rc-rain-sticks","title":"Cardboard Tube Rain Sticks","altNames":["rain stick","rainmaker craft","homemade rain stick","tube shaker"],"type":"Craft","place":"Both","ageMin":9,"ageMax":18,"durationMin":45,"groupMin":null,"groupMax":null,"energy":1,"prep":"Medium","blurb":"Coil a paper obstacle inside a cardboard tube, add rice, and tip it to hear a long, soft rainfall whisper.","materials":["Long cardboard tubes (mailing or paper-towel), 1 per camper","Dry rice or dry beans, a small scoop per camper","Aluminum foil or pipe cleaners for the inner coil","Paper plates or cardboard circles to cap the ends","Masking tape","Markers, paint, yarn to decorate","Scissors"],"materialTags":["Cardboard","Masking tape","Markers","Paint","Yarn","Scissors","Pipe cleaners"],"steps":["Take a long cardboard tube and twist a length of foil or several pipe cleaners into a loose spring, then push it all the way inside as the internal obstacle.","Cap one end by taping a cardboard circle or folded paper firmly over the opening so nothing leaks.","Pour a small scoop of dry rice or beans into the open end and tilt to listen, adjusting the amount until the sound feels like rain.","Cap and tape the second end tightly so the filling is sealed in.","Decorate the outside with paint, markers, and wrapped yarn in earthy patterns.","Slowly tip the rain stick end over end and listen to the long trickling rainfall sound, tuning the coil or filling if needed."],"notes":"The internal coil is what slows the rice and makes the long 'rain' sound, so don't let kids skip it. Tape both end caps thoroughly or rice ends up all over the floor. For older grades, experiment with different fillings and coil tightness to engineer a specific tone, and discuss why the falling grains sound continuous.","safety":"Loose rice and beans are a choking and slipping hazard, so seal both ends with extra tape and sweep up spills immediately; never use anything small enough to inhale near younger campers.","ages":["g46","g79","g1012"],"rating":4,"links":[{"label":"DIY rain stick craft that actually sounds like rain! — Gift of Curiosity","url":"https://www.giftofcuriosity.com/diy-rain-stick-craft/"},{"label":"Our Days Outside: classic summer camp crafts","url":"https://ourdaysoutside.com/15-classic-summer-camp-crafts-for-kids/"}],"variations":["Use a short paper-towel tube and less filling for a quicker, quieter version.","Try different fillings (rice, beans, pony beads) and have campers vote on the most rain-like sound.","For older campers, challenge them to engineer the longest possible 'rainfall' by tuning coil tightness and filling amount, timing each design.","Decorate as a themed instrument and use the finished rain sticks together in a camp song or storytelling soundscape."],"subsets":[["A looser coil that touches the walls slows the grains best"],["Tape a sturdy cap, paper alone tears under shaking"],["Add filling a little at a time and listen as you go"],[],[],["Tip slowly end over end, do not shake, for the true rain sound"]]},
  {"id":"rc-cardboard-staffs","title":"Decorated Adventure Staffs","altNames":["walking staff craft","cardboard staff","adventure staff","hiking stick craft"],"type":"Craft","place":"Both","ageMin":9,"ageMax":15,"durationMin":45,"groupMin":null,"groupMax":null,"energy":1,"prep":"Medium","blurb":"Roll cardboard into a sturdy explorer's staff and wrap it with yarn, beads, and earned 'trail badges'.","materials":["Large cardboard sheets or several stacked tubes per camper","Masking tape","Yarn in earthy colors","Pony beads","Paint and markers","Foam sheet scraps for badges","Glue","Scissors"],"materialTags":["Cardboard","Masking tape","Yarn","Pony beads","Paint","Markers","Foam sheets","Glue","Scissors"],"steps":["Roll a cardboard sheet tightly into a long tube about as tall as your shoulder, or stack and tape several tubes end to end.","Wrap the whole staff in masking tape to lock the roll and make a strong, paintable surface.","Paint or marker a base color and pattern down the length of the staff and let it dry.","Wrap sections with colored yarn, tying off and threading pony beads to make grip bands and dangles.","Cut small foam 'trail badges' shaped like leaves, suns, or animals and glue them on as accomplishments.","Add a yarn wrist loop near the top so the staff is easy to carry on a hike or parade."],"notes":"Rolling tight and taping fully is what keeps the staff from crushing, so check each roll before decorating. This is a great multi-day craft where campers earn and add a new badge after each adventure. For older grades, lean into design: themed crests, a carved-look pattern in marker, or a clan staff the whole cabin co-decorates.","safety":"Long staffs become accidental jousting poles, so set a firm 'staff stays vertical and grounded indoors' rule and space campers well apart during any parade or hike.","ages":["g46","g79"],"rating":4,"links":[{"label":"DIY Yarn Wrapped Sticks — Easy Nature Craft for Kids","url":"https://www.lauraradniecki.com/diy-yarn-wrapped-sticks/"},{"label":"Our Days Outside: classic summer camp crafts","url":"https://ourdaysoutside.com/15-classic-summer-camp-crafts-for-kids/"}],"variations":["Make shorter wand-length staffs for a faster build or a younger crowd.","Turn it into a week-long award staff where a new badge is added after each completed challenge.","For older campers, require a themed heraldic design with a clan name, motto banner, and matching badge set.","Have each cabin co-decorate one giant group staff to carry at the camp closing ceremony."],"subsets":[["Roll as tightly as you can, then have a buddy hold it while you tape"],["Spiral the tape so the whole length is covered and rigid"],[],["Tie yarn off tightly so grip bands do not unravel"],[],["Loop the wrist strap so the staff can hang while hands are busy"]]},
  {"id":"rc-woven-paper-baskets","title":"Woven Paper Baskets","altNames":["paper basket weaving","woven basket craft","construction paper basket","strip-woven basket"],"type":"Craft","place":"Both","ageMin":9,"ageMax":18,"durationMin":60,"groupMin":null,"groupMax":null,"energy":1,"prep":"Medium","blurb":"Weave strips of paper into a flat base, fold the walls up, and lock them into a sturdy little carry basket.","materials":["Sturdy construction paper or thin cardboard in 2-3 colors","Scissors","Glue or masking tape","Markers","Yarn for a handle","A ruler or strip template"],"materialTags":["Paper","Scissors","Glue","Masking tape","Markers","Yarn","Cardboard"],"steps":["Cut several equal-width strips from your paper, keeping them uniform so the weave stays even.","Lay a set of strips side by side and weave a second set across them over-under to form a flat woven square base.","Tape or glue the outer edges of the base so the woven square holds together.","Fold all the strip ends upward along the edges of the square to start the basket walls.","Weave new strips horizontally around the standing wall strips, over-under, gluing the ends as you complete each ring.","Fold the top wall ends down over the last ring and glue to finish the rim, then add a yarn handle through two sides."],"notes":"Uniform strip width is everything; a strip template or pre-cut strips keeps the weave clean and prevents frustration. Folding the walls up neatly is the tricky transition, so demo it slowly. For older grades, use thinner strips for a finer weave, add a color pattern around the walls, or scale up to a sturdy cardboard-strip basket that holds real weight.","safety":"This is scissors-heavy with many strips, so set a cutting zone, keep blades pointed away from the body, and have campers carry scissors tips-down between stations.","ages":["g46","g79","g1012"],"rating":4,"media":[{"title":"DIY Weaved Paper Baskets — step-by-step weaving tutorial (video)","url":"https://www.youtube.com/watch?v=LGRHcKC_Hyo"}],"links":[{"label":"Our Days Outside: classic summer camp crafts","url":"https://ourdaysoutside.com/15-classic-summer-camp-crafts-for-kids/"}],"variations":["Pre-cut the strips and pre-fold the base creases for younger campers so they focus on weaving.","Use two contrasting colors to create a clear checkerboard pattern in the base and walls.","For older campers, use thin cardboard strips for a load-bearing basket and require a planned multi-color wall pattern.","Weave a shallow tray instead of a tall basket to hold finished crafts or a small plant cup."],"subsets":[["Use a template or ruler so every strip is the same width"],["Start the base over-under and keep the rows pushed tight"],[],["Crease the folds firmly so the walls stand up on their own"],["Glue each ring's ends before starting the next row"],[]]},
];
